import React, { useEffect, useRef, useState } from "react";
import "./EeshaWalkComponent.css";

const EeshaWalkComponent = ({ audioCtx, soundType, onStop }) => {
  const [steps, setSteps] = useState(0);
  const [isSensorsStarted, setIsSensorsStarted] = useState(false);
  const lastStepTime = useRef(0);
  const threshold = 12; // Adjust sensitivity for step detection

  useEffect(() => {
    let sensor;

    const startSensors = async () => {
      try {
        // LinearAccelerationSensor provides motion data without gravity
        sensor = new window.LinearAccelerationSensor({ frequency: 60 });
        
        sensor.addEventListener("reading", () => {
          const { x, y, z } = sensor;
          const magnitude = Math.sqrt(x * x + y * y + z * z);

          // Simple peak detection for steps
          if (magnitude > threshold) {
            const now = Date.now();
            if (now - lastStepTime.current > 350) { // Debounce steps (350ms)
              setSteps((prev) => prev + 1);
              lastStepTime.current = now;
              playClick();
            }
          }
        });

        sensor.start();
        setIsSensorsStarted(true);
      } catch (error) {
        console.error("Sensor error:", error);
        alert("Sensor access denied or not supported on this device.");
      }
    };

    const playClick = () => {
      if (!audioCtx) return;
      
      const oscillator = audioCtx.createOscillator();
      const gainNode = audioCtx.createGain();

      oscillator.connect(gainNode);
      gainNode.connect(audioCtx.destination);

      // Change frequency based on soundType prop
      if (soundType === "marimba") {
        oscillator.type = "sine";
        oscillator.frequency.setValueAtTime(880, audioCtx.currentTime);
      } else {
        oscillator.type = "square";
        oscillator.frequency.setValueAtTime(440, audioCtx.currentTime);
      }

      gainNode.gain.setValueAtTime(0.1, audioCtx.currentTime);
      gainNode.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.1);

      oscillator.start();
      oscillator.stop(audioCtx.currentTime + 0.1);
    };

    startSensors();

    return () => {
      if (sensor) sensor.stop();
    };
  }, [audioCtx, soundType]);

  return (
    <div className="eesha-walk-container">
      <div className="stats-circle">
        <span className="step-count">{steps}</span>
        <span className="step-label">STEPS</span>
      </div>
      
      <div className="sensor-status">
        <div className={`status-dot ${isSensorsStarted ? "active" : ""}`} />
        {isSensorsStarted ? "Sensors Live" : "Initializing..."}
      </div>

      <button className="stop-btn" onClick={onStop}>
        END SESSION
      </button>
    </div>
  );
};

export default EeshaWalkComponent;
